e ) ; lastUpdateTime = millis ( ) ; } } // ======== E-INK INITIALIZATION ======== void eink_init ( ) { USBSerial . println ( "E-Ink Init..." ) ; EPD_4IN2B_V2_Init ( ) ; EPD_4IN2B_V2_Clear ( ) ; delay ( 500 ) ; long Imagesize = SCREEN_W * SCREEN_H / 8 ; BlackImage = ( UBYTE * ) malloc ( Imagesize ) ; RYImage = ( UBYTE * ) malloc ( Imagesize ) ; Paint_NewImage ( BlackImage , SCREEN_W , SCREEN_H , 0 , WHITE ) ; Paint_NewImage ( RYImage , SCREEN_W , SCREEN_H , 0 , WHITE ) ; } // ======== DISPLAY TEXT FUNCTION ======== void displayText ( String message ) { Paint_SelectImage ( BlackImage ) ; Paint_Clear ( WHITE ) ; Paint_SelectImage ( RYImage ) ; Paint_Clear ( WHITE ) ; Paint_SelectImage ( RYImage ) ; Paint_DrawString_EN ( 45 , 80 , "ESP32S3 RECEIVER" , & Font24 , WHITE , RED ) ; Paint_SelectImage ( BlackImage ) ; Paint_DrawString_EN ( 50 , 150 , message . c_str ( ) , & Font24 , BLACK , WHITE ) ; EPD_4IN2B_V2_Display ( BlackImage , RYImage ) ; delay ( 2000 ) ; } // ======== UPDATE DISPLAY EVERY 3 MINUTES ======== void updateDisplay ( float temp ) { char msg [ 64 ] ; if ( temp < - 50 ) { sprintf ( msg , "No Data" ) ; } else { sprintf ( msg , "Temp: %.2f C" , temp ) ; } EPD_4IN2B_V2_Init ( ) ; displayText ( String ( msg ) ) ; EPD_4IN2B_V2_Sleep ( ) ; } Now, I am not going to explain how ESP-NOW works internally; because I have already explained all of that in my previous video and article, in complete detail. So, here’s what you need to do: upload the receiver code first, open the Serial Monitor, and copy the MAC address. Then open the transmitter code, paste the MAC address with the ‘0x’ prefix, and finally upload the transmitter code. I have already uploaded both programs, so let’s go ahead and watch them in action. Practical Demonstration: For testing purposes, I have set the update interval to 2 minutes. So every two minutes, the temperature value is read from the sensor and then printed onto the E-Ink display. And as you already know from my previous article, the printing process on an E-Ink display is a little slow; it takes a few seconds to refresh the screen. But that’s completely normal, because E-Ink is not designed for fast animations; It’s designed for clarity, stability, and ultra-low power. And honestly, that’s the beauty of this technology. Once the value is printed, it just stays there; without consuming almost any power. Now let me apply some heat to the temperature sensor. Let’s wait for the value to update. And there it is; the E-Ink display has refreshed, and the new temperature value is now printed on the screen. Super clean, sharp, and completely readable from any angle. Now watch this. I am going to cut the power completely. And as you can see; the temperature value is still there. This is what makes E-Ink displays so incredible. There’s no backlight, no refresh cycles, no power drain; Just a stable, paper-like image that stays visible even with zero power. Honestly, this is one of those things that never stops amazing me. Imagine using a tiny Li-Po battery and still getting months of operation. For off-grid sensors, weather stations, meters, timers; this is absolutely perfect. Alright, now that we have tested the ESP-NOW version successfully. Let’s take a look at the second method; sending temperature data through the IP address. IP Address Method: This is the transmitter-side code. You can see the temperature sensor is still connected to GPIO 4 , just like before. Transmitter Code: #include <WiFi.h>
#include <OneWire.h>
#include <DallasTemperature.h>

// GPIO where the DS18B20 is connected to
const int oneWireBus = 4;     

// Setup a oneWire instance to communicate with any OneWire devices
