UBYTE *BlackImage, *RYImage;
WiFiServer server(80);

float latestTemperature = -100.0;
unsigned long lastUpdateTime = 0;
unsigned long refreshInterval = REFRESH_INTERVAL_MIN * 60 * 1000UL;

// =========================================================

void setup() {
  USBSerial.begin(115200);
  USBSerial.println("ESP32-S3 E-Ink Text Receiver Starting...");

  DEV_Module_Init();
  eink_init();

  // Wi-Fi setup
  WiFi.mode(WIFI_STA);
  WiFi.begin(WIFI_SSID, WIFI_PASS);
  USBSerial.print("Connecting to WiFi");
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    USBSerial.print(".");
  }
  USBSerial.println();
  USBSerial.print("Connected! IP: ");
  USBSerial.println(WiFi.localIP());

  server.begin();
  displayText("Waiting for Data...");
  lastUpdateTime = millis();
}

// =========================================================

void loop() {
  WiFiClient client = server.available();

  if (client) {
    USBSerial.println("Client connected!");
    String requestData = "";

    while (client.connected()) {
      while (client.available()) {
        char c = client.read();
        if (c == '\n') {

          // Save latest received value (but DO NOT refresh display yet)
          latestTemperature = requestData.toFloat();
          USBSerial.print("Received: ");
          USBSerial.println(latestTemperature);
          client.println("ACK");
          client.stop();
          break;

        } else {
          requestData += c;
        }
      }
    }
  }

  // === REFRESH EVERY 3 MINUTES ONLY ===
  if (millis() - lastUpdateTime >= refreshInterval) {
    USBSerial.println("2-minute refresh triggered.");
    updateDisplay(latestTemperature);
    lastUpdateTime = millis();
  }
}

